        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            int sum = 0;
            for (int i = 0; i < N; i++) {
                sum += arr[i];
            }
            if (sum % N == 0) {
                System.out.println("1");
                System.out.println("1");
            } else {
                int found = 0;
                for (int i = 0; i < N; i++) {
                    if (arr[i] % N == 0) {
                        System.out.println("1");
                        System.out.println(i + 1);
                        found = 1;
                        break;
                    }
                }
                if (found == 0) {
